export type Customer = { yearsWithMHPCO: number };
export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};
export type QuoteInput = { items: Item[] };
export type QuoteResult = { premium: number };

export const quote = (
  _customer: Customer,
  _input: QuoteInput,
  _contractIndex: number,
): QuoteResult => {
  return undefined as unknown as QuoteResult;
};

export type Damage = { itemType: string; amount: number };
export type Incident = { cause?: string; damages: Damage[] };
export type ClaimInput = { policy: number; incident: Incident };
export type ClaimResult = { payout: number; remainingCap: number };

export const claim = (
  _policy: { items: Item[]; cap: number; remainingCap: number },
  _incident: Incident,
): ClaimResult => {
  return undefined as unknown as ClaimResult;
};

