export type Customer = { yearsWithMHPCO: number };
export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};
export type QuoteInput = { items: Item[] };
export type QuoteResult = { premium: number };

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export const quote = (
  _customer: Customer,
  input: QuoteInput,
  _contractIndex: number,
): QuoteResult => {
  const item = input.items[0];
  const base = BASE_PREMIUM[item.type];
