    const result = quote(
      { yearsWithMHPCO: 0 },
      { items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }] },
      0,
    );
    // 100 * 1.3 * 1.1 = 143 + 5 = 148
    expect(result.premium).toBe(148);
  });
  it.todo("applies 20% loyalty discount for long-standing customer (>= 2 years)");
  it.todo("applies 10% first insurance surcharge when it's the customer's first contract");
  it.todo("applies 15% repeat-contract discount on contracts after the first");
  it.todo("rounds total premium up to whole G in MHPCO's favor");
  it.todo("sums premiums across multiple items in one quote");
});

describe("MHPCO Claim", () => {
  it.todo("pays damage minus 100 G deductible");
  it.todo("reimburses dragon material damage fully (minus deductible)");
  it.todo("reimburses high-enchantment (>= 8) damage at 50% (minus deductible)");
  it.todo("caps total payout at twice the insurance sum across multiple claims");
  it.todo("reports remainingCap after each claim");
});

